-- ============================================================
-- PRO MOD LOGBOOK — COMPREHENSIVE INCREMENTAL MIGRATION
-- ============================================================
-- Run this ONE script in the Supabase SQL Editor to fix ALL
-- missing tables, columns, indexes, and RLS policies.
--
-- Safe to run multiple times: uses IF NOT EXISTS / IF NOT EXISTS
-- on every statement.
--
-- Generated by comparing EVERY TypeScript interface, database.ts
-- converter, UI form field, and edge function payload against the
-- existing supabase_schema.sql.
-- ============================================================

-- 0. EXTENSIONS
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================================
-- 1. user_profiles — ADD MISSING user_id COLUMN
-- ============================================================
-- CRITICAL: AuthContext.tsx fetchProfile() queries .eq('user_id', userId)
-- and ensureProfile() inserts { user_id: userId }, but the table only
-- has `id` as the primary key. We add a `user_id` column that mirrors `id`.
ALTER TABLE public.user_profiles
  ADD COLUMN IF NOT EXISTS user_id UUID;

-- Backfill user_id from id for any existing rows
UPDATE public.user_profiles
  SET user_id = id
  WHERE user_id IS NULL;

-- Add a default so new rows auto-populate user_id
-- (Cannot use ALTER COLUMN SET DEFAULT with IF NOT EXISTS, so wrap in DO block)
DO $$ BEGIN
  -- Only set default if not already set
  IF NOT EXISTS (
    SELECT 1 FROM pg_attrdef ad
    JOIN pg_attribute a ON a.attrelid = ad.adrelid AND a.attnum = ad.adnum
    JOIN pg_class c ON c.oid = a.attrelid
    WHERE c.relname = 'user_profiles' AND a.attname = 'user_id'
    AND pg_get_expr(ad.adbin, ad.adrelid) LIKE '%auth.uid()%'
  ) THEN
    ALTER TABLE public.user_profiles ALTER COLUMN user_id SET DEFAULT auth.uid();
  END IF;
END $$;

-- Create index on user_id for fast lookups
CREATE INDEX IF NOT EXISTS idx_user_profiles_user_id ON public.user_profiles(user_id);

-- Add unique constraint on user_id (safe: wrapped in DO block)
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'user_profiles_user_id_unique'
  ) THEN
    ALTER TABLE public.user_profiles ADD CONSTRAINT user_profiles_user_id_unique UNIQUE (user_id);
  END IF;
EXCEPTION WHEN others THEN
  RAISE NOTICE 'user_profiles_user_id_unique constraint already exists or cannot be created: %', SQLERRM;
END $$;


