-- ============================================================
-- 4. team_invites — CREATE MISSING TABLE
-- ============================================================
-- Used by: send-team-invite edge function, teamMembership.ts
-- The edge function inserts invites and the frontend reads them.
CREATE TABLE IF NOT EXISTS public.team_invites (
  id              UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  team_owner_id   UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  email           TEXT NOT NULL,
  role            TEXT DEFAULT 'Crew',
  permissions     JSONB DEFAULT '["view"]'::jsonb,
  token           TEXT NOT NULL,
  status          TEXT DEFAULT 'pending',        -- pending, accepted, expired, revoked
  invited_by_name TEXT,
  team_name       TEXT,
  created_at      TIMESTAMPTZ DEFAULT NOW(),
  expires_at      TIMESTAMPTZ DEFAULT (NOW() + INTERVAL '7 days'),
  accepted_at     TIMESTAMPTZ
);

ALTER TABLE public.team_invites ENABLE ROW LEVEL SECURITY;

-- RLS: Team owners can manage their own invites
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Owners manage own team_invites' AND tablename = 'team_invites') THEN
    CREATE POLICY "Owners manage own team_invites"
      ON public.team_invites FOR ALL
      USING (auth.uid() = team_owner_id)
      WITH CHECK (auth.uid() = team_owner_id);
  END IF;
END $$;

-- RLS: Service role (edge functions) can also manage invites
-- The send-team-invite function uses the service role key, so it bypasses RLS.
-- But we also need a policy for users to read invites sent TO them (by email).
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Users can view invites sent to them' AND tablename = 'team_invites') THEN
    CREATE POLICY "Users can view invites sent to them"
      ON public.team_invites FOR SELECT
      USING (
        auth.uid() = team_owner_id
        OR email = (SELECT email FROM auth.users WHERE id = auth.uid())
      );
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_team_invites_owner    ON public.team_invites(team_owner_id);
CREATE INDEX IF NOT EXISTS idx_team_invites_token    ON public.team_invites(token);
CREATE INDEX IF NOT EXISTS idx_team_invites_email    ON public.team_invites(email);
CREATE INDEX IF NOT EXISTS idx_team_invites_status   ON public.team_invites(status);


-- ============================================================
-- 5. team_memberships — CREATE MISSING TABLE
-- ============================================================
-- Used by: AuthContext.tsx (checkTeamMembership), teamMembership.ts
-- Links a Supabase auth user to a team owner's data.
CREATE TABLE IF NOT EXISTS public.team_memberships (
  id               UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  team_owner_id    UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  member_user_id   UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  team_member_id   TEXT,                         -- Optional link to team_members.id
  role             TEXT DEFAULT 'Crew',
  permissions      JSONB DEFAULT '["view"]'::jsonb,
  status           TEXT DEFAULT 'active',        -- active, suspended, removed
  joined_at        TIMESTAMPTZ DEFAULT NOW(),
  invite_id        UUID,                         -- Link back to team_invites.id
  created_at       TIMESTAMPTZ DEFAULT NOW(),
  updated_at       TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE public.team_memberships ENABLE ROW LEVEL SECURITY;

-- Unique constraint: one membership per user per team
DO $$ BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'team_memberships_unique_member'
  ) THEN
    ALTER TABLE public.team_memberships
      ADD CONSTRAINT team_memberships_unique_member
      UNIQUE (team_owner_id, member_user_id);
  END IF;
EXCEPTION WHEN others THEN
  RAISE NOTICE 'team_memberships_unique_member constraint issue: %', SQLERRM;
END $$;

-- RLS: Team owners can manage memberships for their team
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Owners manage team_memberships' AND tablename = 'team_memberships') THEN
    CREATE POLICY "Owners manage team_memberships"
      ON public.team_memberships FOR ALL
      USING (auth.uid() = team_owner_id)
      WITH CHECK (auth.uid() = team_owner_id);
  END IF;
END $$;

-- RLS: Members can view their own membership records
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Members can view own memberships' AND tablename = 'team_memberships') THEN
    CREATE POLICY "Members can view own memberships"
      ON public.team_memberships FOR SELECT
      USING (auth.uid() = member_user_id);
  END IF;
END $$;

-- RLS: Members can insert their own membership (when accepting an invite)
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Members can insert own membership' AND tablename = 'team_memberships') THEN
    CREATE POLICY "Members can insert own membership"
      ON public.team_memberships FOR INSERT
      WITH CHECK (auth.uid() = member_user_id);
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_team_memberships_owner   ON public.team_memberships(team_owner_id);
CREATE INDEX IF NOT EXISTS idx_team_memberships_member  ON public.team_memberships(member_user_id);
CREATE INDEX IF NOT EXISTS idx_team_memberships_status  ON public.team_memberships(status);


